import json
from collections import Counter, defaultdict
initial=json.load(open('data/initial_inventory.json'))
jobs=[json.loads(l) for l in open('data/jobs_seed.jsonl') if l.strip()]
print('deliveries', len(jobs), 'distinct job_ids', len({j['job_id'] for j in jobs}))
print('duplicates', sum(c-1 for c in Counter(j['job_id'] for j in jobs).values() if c>1), 'duplicate job ids', sum(1 for c in Counter(j['job_id'] for j in jobs).values() if c>1))
