print('invalid deliveries', len(invalid), 'distinct invalid ids', len({j['job_id'] for j in invalid}))
byid={}
conflicts=[]
for j in jobs:
    old=byid.setdefault(j['job_id'], j)
    if (old['sku'], old['qty']) != (j['sku'], j['qty']): conflicts.append((old,j))
print('conflicting duplicate payloads', len(conflicts))
expected=initial.copy()
valid_distinct=[]
for jid,j in byid.items():
    if isinstance(j.get('qty'), int) and j['qty']>0:
        valid_distinct.append(j)
for j in valid_distinct:
    if expected.get(j['sku'],0) >= j['qty']:
        expected[j['sku']]-=j['qty']
print('expected valid distinct positive replay:')
print(json.dumps(dict(sorted(expected.items())), indent=2))
invalid_effect=defaultdict(int)
for j in byid.values():
    if isinstance(j.get('qty'), int) and j['qty']<=0:
        invalid_effect[j['sku']] += -j['qty']
print('stock added if invalid accepted once', dict(invalid_effect))
print('distinct valid qty by sku', dict(sorted((k,v) for k,v in (lambda d: d)(defaultdict(int)).items())))
qty_by_sku=defaultdict(int)
for j in valid_distinct:
    qty_by_sku[j['sku']]+=j['qty']
print('reserved requested valid distinct qty by sku', dict(sorted(qty_by_sku.items())))
